namespace sv_d5735261c3564f77be13da15db1d40ec.Components.Pages;

public sealed class NotepadInterop : IAsyncDisposable
{
    internal const string ModulePath = "./Components/Pages/Notepad.razor.js";
    internal const string InitMethod = "initialize";
    internal const string SaveMethod = "save";
    internal const string ClearMethod = "clear";
    internal const string SetDirtyMethod = "setDirty";
    internal const string DisposeMethod = "dispose";

    private readonly IJSRuntime _js;
    private IJSObjectReference? _module;

    public NotepadInterop(IJSRuntime js) => _js = js;

    private async ValueTask<IJSObjectReference> GetModuleAsync()
        => _module ??= await _js.InvokeAsync<IJSObjectReference>("import", ModulePath);

    public async ValueTask<NotepadState> InitializeAsync()
    {
        var module = await GetModuleAsync();
        return await module.InvokeAsync<NotepadState>(InitMethod);
    }

    public async ValueTask SaveAsync(string content)
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(SaveMethod, content);
    }

    public async ValueTask ClearAsync()
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(ClearMethod);
    }

    public async ValueTask SetDirtyAsync(bool isDirty)
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(SetDirtyMethod, isDirty);
    }

    public async ValueTask DisposeAsync()
    {
        try
        {
            if (_module is not null)
            {
                await _module.InvokeVoidAsync(DisposeMethod);
                await _module.DisposeAsync();
            }
        }
        catch (JSDisconnectedException) { }
    }
}

public sealed class NotepadState
{
    public string Content { get; set; } = string.Empty;
    public string? LastSavedAt { get; set; }
}

const STORAGE_KEY = 'notepad-content';
const TIMESTAMP_KEY = 'notepad-saved-at';

let beforeUnloadHandler = null;

export function initialize() {
    const content = localStorage.getItem(STORAGE_KEY) ?? '';
    const lastSavedAt = localStorage.getItem(TIMESTAMP_KEY) ?? null;
    return { content, lastSavedAt };
}

export function save(content) {
    const now = new Date().toLocaleTimeString([], {
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit'
    });
    localStorage.setItem(STORAGE_KEY, content);
    localStorage.setItem(TIMESTAMP_KEY, now);
    return now;
}

export function clear() {
    localStorage.removeItem(STORAGE_KEY);
    localStorage.removeItem(TIMESTAMP_KEY);
}

export function setDirty(isDirty) {
    if (isDirty && !beforeUnloadHandler) {
        beforeUnloadHandler = (e) => {
            e.preventDefault();
        };
        window.addEventListener('beforeunload', beforeUnloadHandler);
    } else if (!isDirty && beforeUnloadHandler) {
        window.removeEventListener('beforeunload', beforeUnloadHandler);
        beforeUnloadHandler = null;
    }
}

export function dispose() {
    if (beforeUnloadHandler) {
        window.removeEventListener('beforeunload', beforeUnloadHandler);
        beforeUnloadHandler = null;
    }
}

