@page "/notepad"
@rendermode InteractiveServer
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<div class="notepad-container">
    <textarea class="form-control notepad-textarea"
              @bind="Content"
              @bind:event="oninput"
              @bind:after="OnContentChanged"
              placeholder="Type your notes here..."></textarea>

    <div class="notepad-toolbar">
        <span class="notepad-status text-muted">
            @if (_lastSavedAt is not null)
            {
                <text>Last saved at @_lastSavedAt</text>
            }
            else
            {
                <text>Not yet saved</text>
            }
        </span>

        <div>
            <button class="btn btn-outline-danger" @onclick="ClearAsync">Clear</button>
            <button class="btn btn-primary" @onclick="SaveNowAsync">Save now</button>
        </div>
    </div>
</div>

@code {
    private NotepadInterop? _interop;
    private Timer? _autoSaveTimer;
    private string? _lastSavedAt;
    private string _savedSnapshot = string.Empty;
    private bool _isDirty;

    public string Content { get; set; } = string.Empty;

    protected override void OnInitialized()
    {
        _autoSaveTimer = new Timer(AutoSaveCallback, null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _interop = new NotepadInterop(JS);
            var state = await _interop.InitializeAsync();
            Content = state.Content;
            _savedSnapshot = state.Content;
            _lastSavedAt = state.LastSavedAt;
            StateHasChanged();
        }
    }

    private async Task OnContentChanged()
    {
        var dirty = Content != _savedSnapshot;
        if (dirty != _isDirty)
        {
            _isDirty = dirty;
            if (_interop is not null)
            {
                await _interop.SetDirtyAsync(_isDirty);
            }
        }
    }

    private async void AutoSaveCallback(object? state)
    {
        if (_isDirty)
        {
            await InvokeAsync(async () =>
            {
                await SaveAsync();
                StateHasChanged();
            });
        }
    }

    private async Task SaveNowAsync()
    {
        await SaveAsync();
    }

    private async Task SaveAsync()
    {
        if (_interop is null) return;

        // Save returns the formatted timestamp from JS
        var module = await JS.InvokeAsync<IJSObjectReference>("import", NotepadInterop.ModulePath);
        var timestamp = await module.InvokeAsync<string>(NotepadInterop.SaveMethod, Content);
        await module.DisposeAsync();

        _savedSnapshot = Content;
        _lastSavedAt = timestamp;
        _isDirty = false;
        await _interop.SetDirtyAsync(false);
    }

    private async Task ClearAsync()
    {
        if (_interop is null) return;

        Content = string.Empty;
        _savedSnapshot = string.Empty;
        _lastSavedAt = null;
        _isDirty = false;

        await _interop.ClearAsync();
        await _interop.SetDirtyAsync(false);
    }

    public async ValueTask DisposeAsync()
    {
        if (_autoSaveTimer is not null)
        {
            await _autoSaveTimer.DisposeAsync();
        }

        if (_interop is not null)
        {
            await _interop.DisposeAsync();
        }
    }
}

